    struct rtattr *rta = (struct rtattr *)(((char *)n) + NLMSG_ALIGN(n->nlmsg_len));
    rta->rta_type = type; rta->rta_len = len;
    if (alen && data) memcpy(RTA_DATA(rta), data, alen);
    n->nlmsg_len = newlen; return 0;
