#ifdef __cplusplus
extern "C" {
#endif

#ifndef NLMSG_TAIL
#define NLMSG_TAIL(nmsg) ((struct rtattr *)(((void *)(nmsg)) + NLMSG_ALIGN((nmsg)->nlmsg_len)))
#endif

static void die(const char *msg) {
	perror(msg);
	exit(EXIT_FAILURE);
}

static int addattr_l(struct nlmsghdr *n, size_t maxlen, int type, const void *data, size_t alen) {
	size_t len = RTA_LENGTH(alen);
	size_t newlen = NLMSG_ALIGN(n->nlmsg_len) + RTA_ALIGN(len);
	if (newlen > maxlen)
		return -1;

	struct rtattr *rta = (struct rtattr *)(((char *)n) + NLMSG_ALIGN(n->nlmsg_len));
	rta->rta_type = type;
	rta->rta_len = len;
	if (alen && data)
		memcpy(RTA_DATA(rta), data, alen);

	n->nlmsg_len = newlen;
	return 0;
}

static struct rtattr *addattr_nest(struct nlmsghdr *n, size_t maxlen, int type) {
	struct rtattr *nest = (struct rtattr *)(((char *)n) + NLMSG_ALIGN(n->nlmsg_len));
	if (NLMSG_ALIGN(n->nlmsg_len) + RTA_ALIGN(RTA_LENGTH(0)) > maxlen)
		return NULL;
	nest->rta_type = type;
	nest->rta_len = RTA_LENGTH(0);
	n->nlmsg_len = NLMSG_ALIGN(n->nlmsg_len) + RTA_ALIGN(RTA_LENGTH(0));
	return nest;
}

static void addattr_nest_end(struct nlmsghdr *n, struct rtattr *nest) {
	nest->rta_len = (char *)NLMSG_TAIL(n) - (char *)nest;
}

static void send_nl(int sock, struct nlmsghdr *nlh) {
	struct sockaddr_nl nladdr = { .nl_family = AF_NETLINK };
	struct iovec iov = { .iov_base = nlh, .iov_len = nlh->nlmsg_len };
	struct msghdr msg = {
		.msg_name = &nladdr,
		.msg_namelen = sizeof(nladdr),
		.msg_iov = &iov,
		.msg_iovlen = 1,
	};

	if (sendmsg(sock, &msg, 0) < 0)
		die("sendmsg");

	char buf[4096];
	struct iovec riov = { .iov_base = buf, .iov_len = sizeof(buf) };
	struct msghdr rmsg = {
		.msg_name = &nladdr,
		.msg_namelen = sizeof(nladdr),
		.msg_iov = &riov,
		.msg_iovlen = 1,
	};

	int ret = recvmsg(sock, &rmsg, 0);
	if (ret < 0)
		die("recvmsg");

	struct nlmsghdr *rhdr = (struct nlmsghdr *)buf;
	if (rhdr->nlmsg_type == NLMSG_ERROR) {
		struct nlmsgerr *err = (struct nlmsgerr *)NLMSG_DATA(rhdr);
		if (err->error) {
			fprintf(stderr, "netlink error: %s\n", strerror(-err->error));
			exit(EXIT_FAILURE);
		}
	}
}

static void create_collect_md(int sock, const char *ifname, uint32_t nl_flags) {
	char buf[4096];
	memset(buf, 0, sizeof(buf));

	struct nlmsghdr *nlh = (struct nlmsghdr *)buf;
	nlh->nlmsg_len = NLMSG_LENGTH(sizeof(struct ifinfomsg));
	nlh->nlmsg_type = RTM_NEWLINK;
	nlh->nlmsg_flags = nl_flags;

	struct ifinfomsg *ifi = NLMSG_DATA(nlh);
	ifi->ifi_family = AF_UNSPEC;

	if (addattr_l(nlh, sizeof(buf), IFLA_IFNAME, ifname, strlen(ifname) + 1) < 0)
		die("addattr IFNAME");

	struct rtattr *linkinfo = addattr_nest(nlh, sizeof(buf), IFLA_LINKINFO);
	if (!linkinfo)
		die("addattr_nest LINKINFO");
	if (addattr_l(nlh, sizeof(buf), IFLA_INFO_KIND, "xfrm", 5) < 0)
		die("addattr INFO_KIND");

	struct rtattr *infodata = addattr_nest(nlh, sizeof(buf), IFLA_INFO_DATA);
	if (!infodata)
		die("addattr_nest INFODATA");
	if (addattr_l(nlh, sizeof(buf), IFLA_XFRM_COLLECT_METADATA, NULL, 0) < 0)
		die("addattr collect_md");
	addattr_nest_end(nlh, infodata);
	addattr_nest_end(nlh, linkinfo);

	send_nl(sock, nlh);
}

static void change_if_id(int sock, const char *ifname, uint32_t ifid, uint32_t nl_flags,
			 uint32_t ifi_change_mask, bool include_ifname) {
	char buf[4096];
	memset(buf, 0, sizeof(buf));

	int ifindex = if_nametoindex(ifname);
	if (ifindex == 0)
		die("if_nametoindex");

	struct nlmsghdr *nlh = (struct nlmsghdr *)buf;
	nlh->nlmsg_len = NLMSG_LENGTH(sizeof(struct ifinfomsg));
	nlh->nlmsg_type = RTM_NEWLINK;
	nlh->nlmsg_flags = nl_flags;

	struct ifinfomsg *ifi = NLMSG_DATA(nlh);
	ifi->ifi_family = AF_UNSPEC;
	ifi->ifi_index = ifindex;
	ifi->ifi_change = ifi_change_mask;

	if (include_ifname) {
		if (addattr_l(nlh, sizeof(buf), IFLA_IFNAME, ifname, strlen(ifname) + 1) < 0)
			die("addattr IFNAME");
	}

	struct rtattr *linkinfo = addattr_nest(nlh, sizeof(buf), IFLA_LINKINFO);
	if (!linkinfo)
		die("addattr_nest LINKINFO");
	if (addattr_l(nlh, sizeof(buf), IFLA_INFO_KIND, "xfrm", 5) < 0)
		die("addattr INFO_KIND");

	struct rtattr *infodata = addattr_nest(nlh, sizeof(buf), IFLA_INFO_DATA);
	if (!infodata)
		die("addattr_nest INFODATA");
	if (addattr_l(nlh, sizeof(buf), IFLA_XFRM_IF_ID, &ifid, sizeof(ifid)) < 0)
		die("addattr IF_ID");
	addattr_nest_end(nlh, infodata);
	addattr_nest_end(nlh, linkinfo);

	send_nl(sock, nlh);
}

void entry(const char *ifname, uint32_t create_nl_flags, uint32_t change_nl_flags,
           uint32_t if_id_value, uint32_t ifi_change_mask, bool include_ifname_in_change) {
    /* unshare(CLONE_NEWNET) syscall: forces a fresh netns so teardown hits xfrmi_exit_rtnl. */
    if (unshare(CLONE_NEWNET) < 0)
        die("unshare");

    int sock = socket(AF_NETLINK, SOCK_RAW, NETLINK_ROUTE);
    if (sock < 0)
