static int xfrmi_changelink(struct net_device *dev, struct nlattr *tb[],
                           struct nlattr *data[],
                           struct netlink_ext_ack *extack)
{
        struct xfrm_if *xi = netdev_priv(dev);
        struct net *net = xi->net;
