                return -EINVAL;
        }

        xi = xfrmi_locate(net, &p);
        if (!xi) {
                xi = netdev_priv(dev);
        } else {
                if (xi->dev != dev)
                        return -EEXIST;
                if (xi->p.collect_md) {
                        NL_SET_ERR_MSG(extack,
                                       "device can't be changed to collect_md");
                        return -EINVAL;
                }
