+
+static struct rtattr *addattr_nest(struct nlmsghdr *n, size_t maxlen, int type) {
+	struct rtattr *nest = (struct rtattr *)(((char *)n) + NLMSG_ALIGN(n->nlmsg_len));
+	if (NLMSG_ALIGN(n->nlmsg_len) + RTA_ALIGN(RTA_LENGTH(0)) > maxlen)
+		return NULL;
